INSERT INTO quiz_categories (id, title, description, seo_description, icon, enabled, badge_json, sort_order) VALUES ('test', 'Test', 'Interner Schnelltest', 'Test Quiz - Interner Schnelltest mit kurzen Beispiel-Fragen zum Format. Ideal, um den Ablauf, die Punkte-Logik und die Bedienung kennenzulernen. Du bekommst ein Gefühl für die Fragearten, den zweiten Versuch und die Rückmeldungen. Perfekt zum schnellen Check, ob alles funktioniert und wie sich das Quiz anfühlt.', 'images/website/kategorie/kategorie-hamburg-nacht.png', 1, '{"active":true,"text":"Neu"}', 10);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('test', '1. EASY Wie heißt das unter Touristen beliebte scheibenförmige Relief?', '["Das Auge der Weisheit","Der Mund der Wahrheit","Die Nase der Würde","Der Nichtsehende"]', 1, 'easy', 'image', '/images/italien/rom/rom-mund-der-wahrheit.png', '["Antike","Test"]', 'Am Eingang der Kirche Santa Maria ...', 1, 10);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('test', '2. HERO Wie heißt das unter Touristen beliebte scheibenförmige Relief?', '["Das Auge der Weisheit","Der Mund der Wahrheit","Die Nase der Würde","Der Nichtsehende"]', 1, 'hero', 'image', '/images/italien/domitianus.png', '["Antike","Test"]', 'Am Eingang der Kirche Santa Maria ...', 1, 20);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('test', '3. MEDIUM Wie heißt das unter Touristen beliebte scheibenförmige Relief?', '["Das Auge der Weisheit","Der Mund der Wahrheit","Die Nase der Würde","Der Nichtsehende"]', 1, 'medium', 'image', '/images/italien/vatikan/vatikan-vatikanische bibliothek.png', '["Antike","Test"]', 'Am Eingang der Kirche Santa Maria ...', 1, 30);
INSERT INTO quiz_categories (id, title, description, seo_description, icon, enabled, badge_json, sort_order) VALUES ('rom', 'Rom', 'Kolosseum, Forum & Co.', 'Rom Quiz - Kolosseum, Forum & Co. Entdecke Geschichte, Architektur und Sehenswürdigkeiten der Ewigen Stadt in diesem Quiz. Von der Antike bis zur Renaissance lernst du wichtige Bauwerke, Kaiser und Schauplätze kennen. Die Fragen decken Kultur, Alltag und Hintergründe ab und bringen dir Rom in kompakten Etappen näher.', 'images/website/kategorie/kategorie-rom-2.png', 1, '{"active":true,"text":"Neue Fragen"}', 20);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches berühmte römische Bauwerk ist auf diesem Bild zu sehen?', '["Amphitheatrum Flavium","Pantheon","Circus Maximus","Forum Romanum"]', 0, 'easy', 'image', '/images/italien/rom/rom-kolosseum.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Die antike Bezeichnung Amphitheatrum Flavium, heute auch bekannt als Kolosseum, leitet sich von der flavischen Dynastie der Kaiser Vespasian, Titus und Domitian ab, die den Bau initiierten und vollendeten.', 1, 10);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie hieß der römische Kaiser, der den Bau des Kolosseums in Auftrag gab?', '["Vespasian","Nero","Trajan","Hadrian"]', 0, 'medium', 'image', '/images/italien/titus_flavius_vespasian.png', '["Antike","Italien","Geschichte"]', NULL, 1, 20);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie viele Eingänge besaß das Kolosseum?', '["50","120","10","80"]', 3, 'medium', 'text', NULL, '["Antike","Italien","Geschichte","Architektur"]', 'Das Kolosseum besaß etwa 80 Ein- (und Aus-)gänge. So konnten die Menschenmassen schnell hinein- und wieder hinauskommen.', 1, 30);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', ' Woher stammt der Name Kolosseum ab?', '["Von der Form des Gebäudes","Von der Lage auf einem Hügel namens Kolossus","Von der Größe der Gladiatoren","Von einer gigantischen Statue in der Nähe"]', 3, 'medium', 'text', NULL, '["Antike","Italien","Geschichte"]', 'Der Name stammt nicht von seiner Größe ab, sondern weil es nebenan eine riesige Statue des Kaisers Nero stand, der sogenannte Kolossal des Nero', 1, 40);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche innovative architektonische Technik wurde beim Bau des Kolosseums verwendet, um die massive Struktur zu stützen und gleichzeitig ein beeindruckendes Design zu ermöglichen?', '["Gewölbter Beton","Hypokausten-System","Aquädukt-Technik","Säulenarchitektur"]', 0, 'easy', 'text', NULL, '["Antike","Italien","Geschichte","Architektur"]', NULL, 1, 50);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Kaiser erweiterte das Kolosseum durch den Bau des vierten Rangs?', '["Kaiser Domitian","Kaiser Vespasian","Kaiser Titus","Kaiser Hadrian"]', 0, 'hero', 'image', '/images/italien/domitianus.png', '["Antike","Italien","Geschichte","Architektur"]', 'Kaiser Domitian, der jüngere Bruder von Kaiser Titus, erweiterte das Kolosseum durch den Bau des vierten Rangs, um den unteren Gesellschaftsschichten den Besuch von Veranstaltungen zu ermöglichen.', 1, 60);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Das Kolosseum war bekannt für seine aufwändigen Inszenierungen. Welcher Begriff beschreibt die nachgestellten Seeschlachten, die im gefluteten Kolosseum vermutlich stattfanden?', '["Nautica","Maritima","Aquatica","Naumachia"]', 3, 'hero', 'image', '/images/italien/naumachia-colosseum.png', '["Antike","Italien","Geschichte"]', NULL, 1, 70);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher römische Kaiser war Zeuge der Fertigstellung des Kolosseums und weihte es mit einer Feier ein, die 100 Tage dauerte?', '["Kaiser Vespasian","Kaiser Titus","Kaiser Trajan","Kaiser Domitian"]', 1, 'medium', 'image', '/images/italien/kaiser-titus.png', '["Antike","Italien","Geschichte"]', NULL, 1, 80);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Rolle spielte die sogenannte ''Hypogeum''-Struktur im Kolosseum, die nach der ursprünglichen Konstruktion hinzugefügt wurde?', '["Unterirdische Räume für Tiere und Gladiatoren","Verstärkung der Außenwände","Erweiterung der Zuschauerplätze","Einbau von Kaisersitzen"]', 0, 'medium', 'text', NULL, '["Antike","Italien","Geschichte"]', 'Es ermöglichte den schnellen und dramatischen Auftritt während der Spiele. Mit Hebevorrichtungen und Falltüren konnten Tiere und Kämpfer direkt in die Arena gebracht werden, was die Inszenierungen noch spektakulärer machte.', 1, 90);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Architekt begann den Bau des Trevi-Brunnens im Jahr 1732, obwohl der Brunnen erst nach seinem Tod im Jahr 1762 fertiggestellt wurde?', '["Luigi Vanvitelli","Carlo Fontana","Gian Lorenzo Bernini","Nicola Salvi"]', 3, 'hero', 'image', '/images/italien/rom/rom-trevi-brunnen.png', '["Antike","Italien","Geschichte"]', ' ', 1, 100);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Der Trevi-Brunnen steht am Endpunkt eines antiken römischen Aquädukts, der Rom seit der Antike mit Wasser versorgt. Wie heißt dieser Aquädukt?', '["Aqua Claudia","Aqua Virgo","Aqua Anio Novus","Aqua Appia"]', 1, 'hero', 'image', '/images/italien/aqua-virgo.png', '["Antike","Italien","Geschichte","Architektur"]', NULL, 1, 110);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche zentrale Figur des Trevi-Brunnens, die auf einem Muschelwagen steht, wird von zwei Tritonen flankiert?', '["Poseidon","Triton","Neptun","Oceanus"]', 2, 'easy', 'image', '/images/italien/rom/rom-trevi-brunnen.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Architektur"]', NULL, 1, 120);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Symbolik steht hinter dem Werfen einer Münze über die linke Schulter in den Trevi-Brunnen?', '["Rückkehr nach Rom","Wunscherfüllung","Langes Leben","Ewige Liebe finden"]', 0, 'easy', 'image', '/images/italien/rom/rom-trivi-brunnen-muenzwurf.png', '["Italien"]', NULL, 1, 130);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher italienische Papst beauftragte die Fertigstellung des Trevi-Brunnens und ist auf einer Inschrift am Brunnen verewigt?', '["Papst Alexander VII","Papst Urban VIII","Papst Sixtus V","Papst Clemens XII"]', 3, 'hero', 'image', '/images/italien/papst-clemens -XII.png', '["Italien","Sehenswürdigkeit","Religion","Geschichte"]', NULL, 1, 140);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche der folgenden Statuen am Trevi-Brunnen symbolisiert die „Fruchtbarkeit“, die aus der Reinheit des Wassers hervorgeht?', '["Statue der Abundantia","Statue der Salubrity","Statue der Aequitas","Statue der Nymphe"]', 0, 'hero', 'image', '/images/italien/rom/rom-trevi-statue.png', '["Italien","Sehenswürdigkeit","Architektur"]', NULL, 1, 150);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt der berühmte Brunnen auf diesem Bild?', '["Triton-Brunnen","Vierströmebrunnen","Trevi-Brunnen","Neptunbrunnen"]', 2, 'easy', 'image', '/images/italien/rom/rom-trevi-brunnen.png', '["Italien","Sehenswürdigkeit","Architektur"]', NULL, 1, 160);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Tempel im Forum Romanum, der Julius Caesar gewidmet ist, markiert den Ort, an dem sein Leichnam verbrannt wurde?', '["Tempel der Venus und Roma","Tempel des Vesta","Tempel des Divus Iulius","Tempel des Saturn"]', 2, 'hero', 'image', '/images/italien/rom/rom-tempel-des-divus-lulius.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit"]', 'Der Tempel ist weitgehend zerstört, da gerade dieses Areal in Renaissance und Barock als Steinbruch genutzt wurde. Lediglich die drei mächtigen Kerne des Tempelpodiums sind erhalten.', 1, 170);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche antike Straße, die durch das Forum Romanum verläuft, war der traditionelle Weg für Triumphzüge römischer Generäle?', '["Via Sacra","Via Aurelia","Via Flaminia","Via Appia"]', 0, 'medium', 'image', '/images/italien/rom/rom-forum-romanum-viasacra.png', '["Antike","Italien","Geschichte"]', 'Die Via Sacra (heilige Straße) war der Hauptweg des Forum Romanum. Sie führte vom Kolosseum zum Kapitol.', 1, 180);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche der folgenden Strukturen auf dem Palatin war der Palast des ersten römischen Kaisers Augustus, der als Zentrum der Macht diente?', '["Domus Flavia","Domus Tiberiana","Domus Aurea","Domus Augusti"]', 3, 'hero', 'image', '/images/italien/rom/rom-palatin-domus-augusti.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Architektur"]', NULL, 1, 190);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche der Säulen im Forum Romanum wurde zu Ehren eines Kaisers errichtet, der eine bedeutende Niederlage der Goten erzielte und ein Reformprogramm zur Stabilisierung des Reiches durchführte?', '["Trajanssäule","Marcus-Aurelius-Säule","Säule des Phokas","Antoninssäule"]', 0, 'medium', 'image', '/images/italien/rom/rom-trajanssaeule.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit"]', NULL, 1, 200);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Triumphbogen im Forum Romanum, ist bekannt für seine detaillierten Reliefs?', '["Septimius-Severus-Bogen","Titusbogen","Konstantinsbogen","Trajansbogen"]', 1, 'medium', 'image', '/images/italien/rom/rom-forum-fomanum-titusbogen.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Anlässlich der Vergöttlichung von Kaiser Titus ließ dessen jüngerer Bruder und Nachfolger Domitian den Titusbogen auf dem Forum errichten, der an dessen größten Triumph erinnert: die Niederschlagung eines Judäeraufstandes und die Eroberung Jerusalems.', 1, 210);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches Gebäude auf dem Forum Romanum - ursprünglich als Tempel erbaut - wurde im 7. Jahrhundert in eine christliche Kirche umgewandelt und ist bis heute erhalten?', '["Regia","Curia Julia","Basilika Maxentius","Tempel des Antoninus und der Faustina"]', 3, 'hero', 'image', '/images/italien/rom/rom-tempel-antoninus-pius-faustina.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Religion"]', NULL, 1, 220);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt der Platz, der Mittelpunkt des politischen, wirtschaftlichen, kulturellen und religiösen Lebens im antiken Rom war?', '["Forum Traian","Campo de'' Fiori","Piazza Iulium","Forum Romanum"]', 3, 'easy', 'image', '/images/italien/rom/rom-forum-romanum.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit"]', 'Das Forum Romanum (Römischer Marktplatz) ist das älteste römische Forum.', 1, 230);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Einer der sieben Hügel Roms, welcher heute ein großer archäologischer Park ist und mit dem Forum Romanum verbunden, gilt als ältester bewohnter Teil der Stadt?', '["Palatin","Kapitol","Esquilin","Viminal"]', 0, 'easy', 'image', '/images/italien/rom/rom-palatin-domus-augusti.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit"]', 'Der Palatin war einst eine elegante Wohngegend für römische Eliten, einschließlich Kaiser wie Augustus und Tiberius.', 1, 240);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches natürliche Material, das auch in vielen anderen römischen Bauwerken verwendet wurde, trug maßgeblich zur Stabilität und Langlebigkeit des Kolosseums bei?', '["Travertin","Marmor","Tuffstein","Granit"]', 0, 'medium', 'image', '/images/italien/rom/rom-travertin.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit"]', 'Halb Rom besteht aus Travertin. Kaiser, Päpste, Fürsten und Faschistenführer nutzten den eleganten und dabei ganz pflegeleichten Kalkstein.', 1, 250);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie viele Menschen konnten schätzungsweise im Kolosseum Platz finden, als es in seiner Blütezeit vollständig in Betrieb war?', '["Bis zu 5.000","Bis zu 30.000","Bis zu 50.000","Bis zu 120.000"]', 2, 'easy', 'text', NULL, '["Antike","Italien","Geschichte","Sehenswürdigkeit"]', NULL, 1, 260);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Im Jahr 1349 wurden Teile der südlichen Seite des Kolosseum zerstört, was war die Ursache?', '["Steinraub und Plünderungen","ein Großfeuer","ein verheerendes Erdbeben","architektonische Mängel"]', 2, 'medium', 'text', NULL, '["Antike","Italien","Geschichte","Sehenswürdigkeit"]', NULL, 1, 270);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche der folgenden Strukturen ist nicht in Rom zu finden?', '["Kolosseum","Pantheon","Uffizien","Forum Romanum"]', 2, 'easy', 'text', NULL, '["Italien","Geschichte","Sehenswürdigkeit"]', 'Die Uffizien sind ein Kunstmuseum in Florenz.', 1, 280);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Platz in Rom ist bekannt für seine herausragende Barockarchitektur und seine Kirche Sant''Agnese in Agone?', '["Piazza del Popolo","Piazza Venezia","Piazza Navona","Piazza di Spagna"]', 2, 'easy', 'image', '/images/italien/rom/rom-piazza-navona-sant-agnese-in-agone.png', '["Italien","Sehenswürdigkeit","Architektur","Geschichte"]', NULL, 1, 290);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Platz in Rom wird von der berühmten Fontana dei Quattro Fiumi (Vierströmebrunnen) geschmückt?', '["Piazza del Popolo","Piazza Venezia","Piazza Navona","Piazza di Spagna"]', 2, 'easy', 'image', '/images/italien/rom/rom-vierstroemebrunnen.png', '["Italien","Sehenswürdigkeit","Architektur"]', NULL, 1, 300);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Architekt entwarf den berühmten Vierströmebrunnen (Fontana dei Quattro Fiumi) auf der Piazza Navona?', '["Francesco Borromini","Michelangelo Buonarroti","Carlo Maderno","Gian Lorenzo Bernini"]', 3, 'easy', 'image', '/images/italien/gian-lorenzo-bernini.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Der Brunnen symbolisiert vier große Flüsse der damaligen Welt: den Nil, die Donau, den Ganges und den Río de la Plata.', 1, 310);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Die Piazza Navona wurde auf den Überresten welches antiken römischen Stadions errichtet?', '["Stadion des Domitian","Circus Maximus","Stadion des Augustus","Stadion des Nero"]', 0, 'medium', 'image', '/images/italien/rom/rom-stadium-of-domitian.png', '["Italien","Geschichte","Sehenswürdigkeit"]', 'Die charakteristische längliche Form der Piazza Navona folgt noch heute dem Grundriss des antiken Stadions.', 1, 320);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Flüsse sind durch die Statuen des Vierströmebrunnens auf der Piazza Navona symbolisiert?', '["Tiber, Euphrat, Indus, Amazonas","Seine, Mississippi, Nil, Ganges","Nil, Ganges, Donau, Rio della Plata","Donau, Mississippi, Wolga, Nil"]', 2, 'medium', 'image', '/images/italien/rom/rom-vierstroemebrunnen.png', '["Italien","Sehenswürdigkeit","Architektur"]', NULL, 1, 330);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Kirche auf der Piazza Navona beherbergt das Grab von Papst Innozenz X., der die Gestaltung des Platzes maßgeblich beeinflusste?', '["Santa Maria sopra Minerva","Santa Maria dell''Anima","Sant''Agnese in Agone","San Luigi dei Francesi"]', 2, 'medium', 'image', '/images/italien/rom/rom-kirche-sant-agnese-in-agone-daemmerung.png', '["Italien","Sehenswürdigkeit","Religion","Geschichte"]', NULL, 1, 340);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'In welchem Stil wurde die Kirche Sant''Agnese in Agone auf der Piazza Navona erbaut?', '["Gotik","Renaissance","Neoklassizismus","Barock"]', 3, 'easy', 'image', '/images/italien/rom/rom-piazza-navona-sant-agnese-in-agone.png', '["Italien","Sehenswürdigkeit","Religion","Geschichte"]', NULL, 1, 350);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Einer der dreizehn Obelisken in Rom, steht auf der Piazza Navona. Wie heißt dieser Obelisk?', '["Obelisk Agonale","Obelisk Sallustiano","Obelisk Vaticano","Obelisk Flaminio"]', 0, 'hero', 'image', '/images/italien/rom/rom-piazza-navona-obelisk.png', '["Italien","Sehenswürdigkeit","Architektur"]', 'Der Obelisk steht in der Mitte der Piazza Navona und ist Teil des Vierströmebrunnen von Bernini.', 1, 360);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt der barocker Zierbrunnen auf der nördlichen Piazza Navona?', '["Vierströmebrunnen","Mohrenbrunnen","Neptunbrunnen","Tritonbrunnen"]', 2, 'easy', 'image', '/images/italien/rom/rom-neptunbrunnen.png', '["Italien","Sehenswürdigkeit","Architektur"]', 'Die zentrale Figur zeigt Neptun, den römischen Meeresgott, im Kampf gegen einen Oktopus, umgeben von Nereiden (Meerjungfrauen) und Seepferdchen.', 1, 370);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt der barocker Zierbrunnen auf der südlichen Piazza Navona?', '["Vierströmebrunnen","Tritonbrunnen","Neptunbrunnen","Mohrenbrunnen"]', 3, 'easy', 'image', '/images/italien/rom/rom-mohrenbrunnen.png', '["Italien","Sehenswürdigkeit","Architektur"]', 'Die zentrale Figur, die später von Bernini hinzugefügt wurde, zeigt einen muskulösen „Mohren“ (einen Afrikaner oder Triton), der mit einem Delfin kämpft.', 1, 380);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Papst war verantwortlich für die Umgestaltung der Piazza Navona in den heutigen barocken Platz?', '["Papst Alexander VII.","Papst Urban VIII.","Papst Clemens XI.","Papst Innozenz X."]', 3, 'hero', 'image', '/images/italien/papst-innocent-x.png', '["Italien","Sehenswürdigkeit","Religion","Geschichte"]', NULL, 1, 390);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches berühmte Kunstwerk auf der Piazza Navona stellt den Triumph des Papsttums über die vier bekannten Kontinente der damaligen Zeit dar?', '["Fontana dei Quattro Fiumi","Fontana del Moro","Fontana di Nettuno","Obelisco Agonale"]', 0, 'hero', 'text', NULL, '["Italien","Sehenswürdigkeit","Architektur","Religion","Geschichte"]', 'Fontana dei Quattro Fiumi (Vierströmebrunnen)', 1, 400);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt einer der bekanntesten Plätze im Zentrum von Rom?', '["Piazza del Popol","Piazza Navona","Piazza di Spagna","Piazza Venezia"]', 1, 'easy', 'image', '/images/italien/rom/rom-piazza-navona.png', '["Italien","Sehenswürdigkeit","Architektur"]', 'Der Platz ist bekannt für seine drei beeindruckenden Brunnen, darunter der berühmte Vierströmebrunnen, der von Gian Lorenzo Bernini entworfen wurde.', 1, 410);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche antike Straße führte von Rom bis nach Brindisi?', '["Via Aurelia","Via Salaria","Via Appia","Via Flaminia"]', 2, 'medium', 'image', '/images/italien/rom/rom-via-appia-antica.png', '["Italien","Geschichte","Sehenswürdigkeit"]', 'Die Via Appia Antica, ist die berühmteste und älteste der römischen Straßen, sie wird auch „Regina Viarum“ (Königin der Straßen) genannt.', 1, 420);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Säule in Rom ist im Bild zu sehen?', '["Nerosäule","Hadrianssäule","Trajanssäule","Augustussäule"]', 2, 'medium', 'image', '/images/italien/rom/rom-trajanssaeule.png', '["Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Sie wurde zu Ehren des Kaisers Trajan zum Gedenken an seine Siege in Dakien (dem heutigen Rumänien) errichtet.', 1, 430);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Straße in Rom ist bekannt für ihre prächtigen Gräber?', '["Via Appia","Via Flaminia","Via Aurelia","Via Salaria"]', 0, 'easy', 'text', NULL, '["Italien","Geschichte","Sehenswürdigkeit"]', 'Diese alte Straße, die aus dem 4. Jahrhundert v. Chr. stammt, führt von Rom nach Süditalien und ist gesäumt von monumentalen Gräbern und Katakomben, darunter die Gräber der Familien der römischen Aristokratie und verschiedene historische Nekropolen.', 1, 440);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Villa wurde von Kaiser Hadrian als seine Residenz erbaut?', '["Villa d''Este","Villa Adriana","Villa Medici","Villa Borghese"]', 1, 'medium', 'image', '/images/italien/villa-hadriansvilla.png', '["Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Die Villa Adriana (Hadriansvilla) in Tivoli nahe Rom ist eine weitläufige antike Residenz, die Kaiser Hadrian im 2. Jahrhundert n. Chr. als luxuriösen Rückzugsort errichten ließ. Die Anlage umfasst Tempel, Bibliotheken, Theater und Bäder und spiegelt Hadrians Interesse an der Architektur und den Kulturen des gesamten Römischen Reiches wider.', 1, 450);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wer entwarf das heutige Pantheon?', '["Apollodorus von Damaskus","Vitruvius","Hadrian","Palladio"]', 2, 'medium', 'image', '/images/italien/kaiser-hadrian.png', '["Italien","Geschichte","Sehenswürdigkeit"]', 'Das Pantheon in Rom wurde ursprünglich von Marcus Vipsanius Agrippa entworfen, wurde jedoch durch Brände beschädigt. Kaiser Hadrian war der Bauherr und Hauptverantwortliche für die erneute Gestaltung und den Bau des Pantheons, das um 118-125 n. Chr. fertiggestellt wurde.', 1, 460);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches antike Gebäude in Rom ist für seine bemerkenswerte Kuppel berühmt?', '["Kolosseum","Thermen des Caracalla","Augustusbogen","Pantheon"]', 3, 'easy', 'text', NULL, '["Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Die Kuppel hat einen Durchmesser von 43,3 Metern und ist die größte nicht verstärkte Betonkuppel der Welt.', 1, 470);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher römische Tempel wurde speziell zu Ehren der Götter errichtet?', '["Pantheon","Tempel des Jupiter","Tempel des Mars Ultor","Domus Aurea"]', 0, 'easy', 'text', NULL, '["Italien","Geschichte","Sehenswürdigkeit"]', 'Der Name „Pantheon“ bedeutet „All-Götter“ und reflektiert den Zweck des Tempels als eine allgemeine Verehrungsstätte für alle römischen Götter.', 1, 480);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches architektonische Element des Pantheons ermöglicht es, dass das Licht in den Innenraum eindringt?', '["Die Gewölbedecke","Spezielle Pfeiler","Oculus","Die Apsis"]', 2, 'easy', 'image', '/images/italien/rom/rom-pantheon.png', '["Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Das Oculus ist ein rundes Loch in der Mitte der Kuppel, durch das Tageslicht strömt und einen dramatischen Lichtstrahl auf den Innenraum des Tempels wirft.', 1, 490);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher bedeutende Künstler der italienischen Renaissance wurde im Pantheon beigesetzt?', '["Michelangelo","Hadrian","Raphael","Titian"]', 2, 'medium', 'image', '/images/italien/rom/rom-pantheon-grab-raffael.png', '["Italien","Geschichte","Sehenswürdigkeit"]', NULL, 1, 500);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches antike Bauwerk ist auf dem Bild zu sehen?', '["Pantheon","Tempel des Hadrian","Maison Carrée","Engelsburg"]', 0, 'easy', 'image', '/images/italien/rom/rom-pantheon.png', '["Italien","Geschichte","Sehenswürdigkeit"]', NULL, 1, 510);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt das ursprünglich im 2. Jahrhundert als Mausoleum für Kaiser Hadrian erbaute Gebäude?', '["Engelsburg","Mausoleum der Constantina","Pantheon","Grab des Scipio"]', 0, 'easy', 'image', '/images/italien/rom/rom-engelsburg.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Religion"]', 'Im Mittelalter wurde die Engelsburg zur Festung und Zufluchtsstätte für Päpste umgebaut und über einen geheimen Gang, den Passetto di Borgo, mit dem Vatikan verbunden.', 1, 520);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Struktur diente Nero als Residenz?', '["Palatin","Forum Romanum","Thermen des Caracalla","Domus Aurea"]', 3, 'medium', 'text', NULL, '["Italien","Geschichte","Sehenswürdigkeit","Architektur"]', 'Die Domus Aurea (Goldenes Haus) war eine riesige Palastanlage, die von Kaiser Nero nach dem großen Brand von 64 n. Chr. in Rom erbaut wurde. Die prächtige Residenz erstreckte sich über große Teile des Stadtgebiets und war für ihren Luxus und ihre Opulenz bekannt.', 1, 530);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches Gebäude in Rom beherbergt die Vatikanische Bibliothek?', '["Päpstliche Bibliothek","Vatikanisches Archiv","Vatikanische Kapelle","Vatikanpalast"]', 3, 'medium', 'image', '/images/italien/vatikan/vatikan-vatikanische bibliothek.png', '["Italien","Sehenswürdigkeit","Religion","Geschichte"]', 'Der Biblioteca Apostolica Vaticana (Vatikanische Bibliothek) befindet sich im Vatikanischen Palast (Palazzo Vaticano). Die Bibliothek ist in einem speziellen Gebäudetrakt des Vatikanischen Palastes untergebracht.', 1, 540);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Platz in Rom ist bekannt für seine berühmte Spanische Treppe?', '["Piazza Navona","Piazza Venezia","Piazza del Popolo","Piazza di Spagna"]', 3, 'easy', 'image', '/images/italien/rom/rom-piazza-di-spagna.png', '["Italien","Sehenswürdigkeit","Religion","Geschichte"]', 'An der Piazza di Spagna (übersetzt: Spanischer Platz) verbindet die Spanische Treppe die Kirche Santa Trinità dei Monti mit dem Platz im Zentrum der Stadt.', 1, 550);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche Kirche in Rom ist die Hauptkirche des Papstes?', '["Santa Maria Maggiore","St. Peter''s Basilica","San Giovanni in Laterano","Sant''Agnese in Agone"]', 1, 'easy', 'image', '/images/italien/vatikan/st-peters-basilica.png', '["Italien","Sehenswürdigkeit","Religion","Geschichte"]', NULL, 1, 560);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche berühmte Straße in Rom führt zur spanischen Treppe?', '["Via del Corso","Via dei Condotti","Via Nazionale","Via del Tritone"]', 1, 'medium', 'image', '/images/italien/rom/rom-spanische-treppe.png', '["Italien"]', NULL, 1, 570);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches Paar eines römischen Gottes und eines griechischen Gottes stimmt?', '["Minerva - Athene","Merkur - Zeus","Mars - Venus","Poseidon - Mars"]', 0, 'easy', 'text', NULL, '["Antike","Italien","Geschichte"]', 'Die römische Göttin Minerva hat ihre griechische Entsprechung in Athene (Schutzgöttin).', 1, 580);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welche römischen Münzen gehörten zu wichtigsten der Antike?', '["Florin","Talero","Poundus","Sesterz"]', 3, 'medium', 'image', '/images/italien/sesterz.png', '["Antike","Italien","Geschichte"]', 'Sesterz: Eine große Bronze- oder Kupfermünze, die in der Kaiserzeit populär war. Der Sesterz war ein häufig verwendetes Zahlungsmittel und diente oft auch als Recheneinheit in der Buchhaltung.', 1, 590);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Was erhielten in der Antike römische Kinder wenige Tage nach ihrer Geburt?', '["Amulett","Erbvertrag","Pädagogische Schulbücher","Fußkette"]', 0, 'medium', 'text', NULL, '["Antike","Italien","Geschichte"]', 'Am 9. Tag nach der Geburt erhielten römische Babys ihre Namen und ein Amulett. Die Bulla galt als unheilabwehrend.', 1, 600);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt das unter Touristen beliebte scheibenförmige Relief?', '["Das Auge der Weisheit","Der Mund der Wahrheit ","Die Nase der Würde","Der Nichtsehende"]', 1, 'easy', 'image', '/images/italien/rom/rom-mund-der-wahrheit.png', '["Antike","Italien","Geschichte","Sehenswürdigkeit","Religion"]', 'Am Eingang der Kirche Santa Maria legen die Menschen ihre Hand in den marmornen Mund der Wahrheit (Bocca della Verità). Im Mittelalter soll er der Wahrheitsfindung gedient haben: Wer beim Lügen ertappt wurde, dem biss der Mund der Sage nach die Hand ab.', 1, 610);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Am 29. Juni feiern die Bürger Roms das Fest ihrer Stadtpatrone. Wie heißen sie? ', '["San Sebastiano und San Petro","Borromini und Konstantin","Petrus und Paulus","Heiliger Markus und Heiliger Lukas:"]', 2, 'medium', 'text', NULL, '["Italien","Religion","Sehenswürdigkeit","Geschichte"]', NULL, 1, 620);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welcher Klassiker der römischen Küche hat seinen Ursprung in den alte Arbeitervierteln Roms?', '["Lasagne","Risotto alla Milanese","Fettuccine Alfredo","Cacio e Pepe"]', 3, 'easy', 'text', NULL, '["Essen","Italien","Tradition"]', 'Das Pastagericht besteht hauptsächlich aus Pecorino-Käse und Pfeffer.', 1, 630);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Welches traditionelle römische Gericht, welches aus Artischocken zubereitet wird und in der jüdischen Küche der Stadt seinen Ursprung hat, ist unter dem Namen „Carciofi alla Giudia“ bekannt?', '["Gefüllte Artischocken","Frittierte Artischocken","Geschmorte Artischocken mit Minze","Gebratene Artischocken mit Knoblauch"]', 1, 'medium', 'image', '/images/italien/artischocken.png', '["Essen","Italien","Tradition"]', NULL, 1, 640);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißt der beliebte frittierter Reisball in Rom welcher umhüllt ist mit Eiern und Paniermehl und gefüllt ist mit Tomatenragout und Mozzarellakäse?', '["Suppli","L''arancino","Arancini","Crocchetta"]', 0, 'medium', 'image', '/images/italien/rom/rom-suppli.png', '["Essen","Italien"]', NULL, 1, 650);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie heißen die kleinen, leckeren, süßen Hefebrötchen, die meist mit einer fast unanständigen Menge Sahne gefüllt sind?', '["Suppli","Biscotti","Maritozzo","Panino"]', 2, 'medium', 'image', '/images/italien/maritozz.png', '["Essen","Italien","Tradition"]', NULL, 1, 660);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Wie nennt man das traditionelle römische Gericht, welches aus einem ganzen Schwein besteht, das entbeint, mit Kräutern gefüllt und knusprig gebraten wird?', '["Saltimbocca","Abbacchio alla Romana","Porchetta","Coda alla Vaccinara"]', 2, 'medium', 'image', '/images/italien/rom/rom-porchetta.png', '["Essen","Italien","Tradition"]', NULL, 1, 670);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Die gefüllten Pizza-Sandwiche sind der neueste Food-Trend aus Rom. Wie heißt diese Pizza-Variante?', '["Panzerotto","Trapizzino","Scrocchiarella","Pizzetta"]', 1, 'medium', 'image', '/images/italien/rom/rom-trapizzino.png', '["Essen","Italien"]', NULL, 1, 680);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Dieser Klassiker der italienischen Küche stammt ursprünglich aus Rom, wie heißt er?', '["Risotto alla Milanese","Lasagne alla Bolognese","Spaghetti alla Puttanesca","Penne all''Arrabbiata"]', 3, 'easy', 'image', '/images/italien/rom/rom-penne-all-arrabbiata.png', '["Essen","Italien","Tradition"]', 'Arrabbiata bedeutet auf Italienisch „wütend“. Der Name spielt auf die Schärfe der Sauce an, die einem so richtig einheizen kann – so sehr, dass man beim Essen „vor Wut rot wird“.', 1, 690);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Diese köstlichen viereckigen Pizzaschnitten werden auf großen Blechen gebacken. Wie heißt dieser Pizza-To-Go-Snack?', '["Pizza al Taglio","Pizza Marinara","Pizza Calzone","Pizza Focaccia"]', 0, 'easy', 'image', '/images/italien/rom/rom-pizza-al-taglio.png', '["Essen","Italien","Tradition"]', 'Neben Klassikern wie Pomodoro und Mozzarella findet man auch Beläge wie Kartoffeln und Rosmarin, Kürbis und Speck, oder auch Zucchini und Ziegenkäse.', 1, 700);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('rom', 'Rom liegt in welcher Region Italiens?', '["Toskana","Kampanien","Venetien","Lazio"]', 3, 'easy', 'image', '/images/italien/italien-lazio.png', '["Geographie","Italien"]', 'Die Region Latium unterteilt sich wiederum in fünf Provinzen: Frosinone, Latina, Rieti, Rom und Viterbo.', 1, 710);
INSERT INTO quiz_categories (id, title, description, seo_description, icon, enabled, badge_json, sort_order) VALUES ('neapel', 'Neapel', 'Pizza, Vesuv & Meer', 'Neapel Quiz - Pizza, Vesuv & Meer. Teste dein Wissen zu Kultur, Alltag und Highlights rund um Neapel. Themen wie Geschichte, Kulinarik, Landschaft und berühmte Orte sind genauso dabei wie regionale Besonderheiten. Das Quiz verbindet Stadtleben, Natur und Tradition und bietet abwechslungsreiche Fragen.', 'images/website/kategorie/kategorie-neapel.png', 1, '{"active":false,"text":"Neu"}', 30);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('neapel', 'Welcher berühmte Vulkan ist auf diesem Bild zu sehen?', '["Vesuv","Ätna","Stromboli","Vulcano"]', 0, 'easy', 'image', '/images/italien/neapel/neapel-vesuv.png', '[]', NULL, 1, 10);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('neapel', 'Welches berühmte Gericht stammt ursprünglich aus Neapel und ist heute weltweit bekannt?', '["Ravioli","Lasagne","Spaghetti Carbonara","Pizza"]', 3, 'easy', 'text', NULL, '[]', 'Die erste Pizzeria wurde 1830 in Neapel eröffnet.', 1, 20);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('neapel', 'Welches große, historische Gebäude in Neapel diente als königliche Residenz und ist heute ein Museum?', '["Palazzo Reale","Palazzo dello Spagnolo","Maschio Angioino (Castel Nuovo)","Villa Pignatelli"]', 0, 'easy', 'text', NULL, '[]', 'Der Palazzo liegt am Piazza del Plebiscito und ist ein Meisterwerk barocker und klassizistischer Architektur.', 1, 30);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('neapel', 'Welches historische Theater in Neapel ist bekannt für seine beeindruckende Architektur und seine kulturelle Bedeutung?', '["Teatro di San Carlo","Teatro Nazionale","Teatro di Tordinona","Teatro dell''Opera"]', 0, 'easy', 'image', '/images/italien/neapel/neapel-teatro-di-san-carlo.png', '[]', 'Das Teatro di San Carlo wurde 1737 eröffnet und ist das älteste noch aktive Opernhaus in Europa.', 1, 40);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('neapel', 'Welche berühmte Straße in Neapel ist bekannt für ihre historischen Gebäude und ihre Einkaufsstraßen?', '["Via Toledo","Spaccanapoli","Via San Gregorio Armeno","Via Chiaia"]', 0, 'easy', 'text', NULL, '[]', 'Sie verbindet das Piazza Dante mit dem Piazza del Plebiscito und ist heute ein wichtiges Einkaufs- und Geschäftsviertel', 1, 50);
