INSERT INTO quiz_categories (id, title, description, seo_description, icon, enabled, badge_json, sort_order) VALUES ('florenz', 'Florenz', 'Kunst, Dom & Renaissance', 'Florenz Quiz - Kunst, Dom & Renaissance. Vertiefe dein Wissen über Museen, Bauwerke und die Geschichte der Renaissance. Von berühmten Künstlern bis zu ikonischen Sehenswürdigkeiten umfasst das Quiz Architektur, Kultur und historische Entwicklungen. So lernst du Florenz Schritt für Schritt besser kennen.', 'images/website/kategorie/kategorie-florenz.png', 1, '{"active":false,"text":"Neu"}', 50);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welches berühmte Kunstwerk ist auf diesem Bild zu sehen?', '["David","Venus von Milo","Apollo und Daphne","Der Denker"]', 0, 'easy', 'image', '/images/italien/michelangelo-david.png', '["Italien","Kunst","Renaissance"]', 'Die Statue ist über 5 Meter hoch und zeigt den biblischen Helden David kurz vor dem Kampf gegen Goliath – voller Spannung und Konzentration.', 1, 10);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welches bedeutende Bauwerk in Florenz ist für seine beeindruckende Kuppel bekannt, die von Brunelleschi entworfen wurde?', '["Kathedrale von Florenz","Basilika Santa Croce","Basilika San Lorenzo","Palazzo Vecchio"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-dom-kuppel.png', '["Italien","Architektur","Sehenswürdigkeit","Religion"]', 'Die Kuppel der Kathedrale von Florenz, auch bekannt als „Duomo“, ist ein Meisterwerk der Renaissance-Architektur.', 1, 20);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Wie lautet der offizielle Name des Doms von Florenz?', '["Santa Maria del Fiore","Santa Croce","San Lorenzo","Santa Maria Novella"]', 0, 'easy', 'image', '/images/italien/florenz/florenz-dom.png', '["Architektur","Dom von Florenz"]', NULL, 1, 30);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welcher Architekt entwarf die berühmte Kuppel des Doms von Florenz?', '["Michelangelo","Filippo Brunelleschi","Giotto","Donatello"]', 1, 'easy', 'image', '/images/italien/filippo-brunelleschi.png', '["Architektur","Kuppel"]', 'Filippo Brunelleschi entwickelte eine innovative Bauweise, um die riesige Kuppel ohne traditionelles Holzgerüst zu errichten.', 1, 40);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Wie heißt der Glockenturm neben dem Dom von Florenz?', '["Torre Vecchia","Campanile di Giotto","Campanile Medici","Torre Fiorentina"]', 1, 'medium', 'image', '/images/italien/florenz/florenz-dom-2.png', '["Architektur","Campanile"]', 'Der Bau des Campanile begann 1334 unter Giotto und wurde später von anderen Architekten weitergeführt.', 1, 50);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welche Farben dominieren die Marmorfassade des Doms von Florenz?', '["Weiß, Grün und Rosa","Gelb, Rot und Grau","Schwarz, Weiß und Grau","Blau, Weiß und Gold"]', 0, 'easy', 'text', NULL, '["Material","Architektur"]', 'Die Fassade besteht aus weißem Carrara-Marmor, grünem Prato-Marmor und rosafarbenem Marmor aus der Toskana.', 1, 60);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welcher Person ist der Dom von Florenz gewidmet?', '["Johannes der Täufer","Maria","Petrus","Franziskus"]', 1, 'easy', 'image', '/images/italien/florenz/florenz-dom-fassade-2.png', '["Religion"]', 'Der Name Santa Maria del Fiore verweist auf die Jungfrau Maria.', 1, 70);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welche Form hat der Tambour (zylinderförmiger oder polygonaler Unterbau einer Kuppel) unter der Kuppel des Doms von Florenz?', '["Quadrat","Kreis","Achteck","Sechseck"]', 2, 'medium', 'image', '/images/italien/florenz/florenz-dom-kuppel-2.png', '["Architektur"]', 'Der achteckige Tambour trägt die massive Kuppel und ist von acht großen Rippen strukturiert.', 1, 80);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welches Thema zeigt das große Fresko in der Kuppel des Doms von Florenz?', '["Das Jüngste Gericht","Die Geburt Christi","Die Verkündigung","Die Auferstehung"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-dom-deckenfresko.png', '["Kunst","Fresken"]', 'Das monumentale Fresko wurde von Giorgio Vasari begonnen und später von Federico Zuccari vollendet.', 1, 90);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Wie hoch ist die Kuppel des Florentiner Doms ungefähr bis zur Laterne?', '["116 Meter","90 Meter","150 Meter","75 Meter"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-dom-4.png', '["Architektur","Maße"]', 'Die Kuppel prägt mit etwa 116 Metern Höhe die Skyline von Florenz.', 1, 100);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welcher berühmte weiße Marmor wurde beim Bau des Doms verwendet?', '["Carrara-Marmor","Travertin","Basalt","Granit"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-dom-marmor.png', '["Material"]', 'Carrara-Marmor wird seit der Antike in der Toskana abgebaut und war ein wichtiges Material für Renaissancebauten.', 1, 110);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welcher Künstler begann im 16. Jahrhundert das Fresko in der Domkuppel?', '["Sandro Botticelli","Giorgio Vasari","Leonardo da Vinci","Raphael"]', 1, 'medium', 'image', '/images/italien/giorgio-vasari.png', '["Kunst","Fresken"]', 'Das Fresko des Jüngsten Gerichts wurde 1572 von Giorgio Vasari begonnen.', 1, 120);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welcher Künstler vollendete später das Fresko in der Domkuppel?', '["Caravaggio","Federico Zuccari","Titian","Andrea del Sarto"]', 1, 'medium', 'image', '/images/italien/federico-zuccari.png', '["Kunst","Fresken"]', 'Nach Vasaris Tod übernahm Federico Zuccari die Fertigstellung des monumentalen Freskos.', 1, 130);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Wie hoch ist der Campanile (der Glockenturm) ungefähr?', '["84 Meter","65 Meter","120 Meter","45 Meter"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-dom-glockenturm-2.png', '["Architektur","Campanile"]', 'Der Glockenturm ist etwa 84 Meter hoch und kann über eine Treppe bestiegen werden.', 1, 140);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Warum wurde für den Bau der Domkuppel ein Wettbewerb ausgeschrieben?', '["Es gab lange keine technische Lösung für die riesige Kuppel","Der ursprüngliche Architekt starb plötzlich","Der Papst verlangte neue Pläne","Die Stadt wollte einen neuen Baustil"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-dom-3.png', '["Geschichte","Architektur"]', '1418 wurde ein Wettbewerb organisiert, um eine Lösung für die enorme Spannweite der Kuppel zu finden.', 1, 150);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welcher Künstler gestaltete berühmte Skulpturen für die Fassade und den Domkomplex?', '["Donatello","Raphael","Caravaggio","Bernini"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-dom-prophetenfiguren.png', '["Kunst","Dom von Florenz"]', 'Donatellos Propheten rufen das Volk zur Umkehr und verkünden Gottes Strafgericht über die Sünde.', 1, 160);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welches Gebäude bildet zusammen mit Dom und Campanile den berühmten Domkomplex?', '["Baptisterium","Palazzo Vecchio","Uffizien","Santa Croce"]', 0, 'easy', 'image', '/images/italien/florenz/florenz-baptisterium.png', '["Architektur","Dom von Florenz"]', 'Der Domkomplex besteht aus Kathedrale, Baptisterium und Campanile.', 1, 170);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Welches Symbol der Stadt Florenz spiegelt sich im Namen ''Santa Maria del Fiore'' wider?', '["Die Lilie","Der Löwe","Der Adler","Der Turm"]', 0, 'medium', 'text', NULL, '["Architektur","Dom von Florenz"]', 'Die Lilie ist das historische Wappenzeichen von Florenz und gab der Kathedrale ihren Namen.', 1, 180);
INSERT INTO quiz_questions (category_id, question, answers_json, correct_index, difficulty, question_type, image_url, tags_json, background_knowledge, active, sort_order) VALUES ('florenz', 'Wie heißt das Baptisterium gegenüber dem Dom von Florenz?', '["San Giovanni","San Marco","San Lorenzo","Santa Croce"]', 0, 'medium', 'image', '/images/italien/florenz/florenz-baptisterium-nacht.png', '["Baptisterium"]', 'Das Baptisterium San Giovanni gehört zu den ältesten Gebäuden von Florenz.', 1, 190);
