INSERT INTO quiz_feedback (feedback_key, messages_json) VALUES ('correctSecondTry', '["Wow, das hat ja gedauert...","Endlich! Hast du noch mehr Zeit verschwendet?","Na toll, hast du es jetzt?","Puh, das war knapp. Oder auch nicht.","Naja, besser spät als nie, oder?","Oh, du hast es doch noch geschafft. Glück gehabt.","Das war ja gerade so akzeptabel.","Gut gemacht. Oder so ähnlich.","Da ist sie ja, die richtige Antwort. Schön für dich.","Wow, du hast es doch noch gefunden. Beeindruckend... nicht.","Endlich mal eine richtige Antwort, nach all der Zeit.","Das war ja fast schon zu erwarten, irgendwann.","Super, du hast es geschafft. Kaum zu glauben.","Na endlich mal eine richtige Antwort. Bist du stolz?","Puh, war das schwer, oder etwa nicht?","Nicht schlecht für dich, so im zweiten Anlauf.","Wow, das war fast schon zu einfach für dich, oder?","Das war ja gerade so in Ordnung.","Naja, hat ja nur ein Versuch gebraucht. Oder zwei.","Und da haben wir sie, die Antwort. Endlich.","Hättest du das nicht schneller finden können?","Na bitte, geht doch. Irgendwann.","Du hast es also doch noch geschafft. Bravo.","Tada, die richtige Antwort. Fast wie erwartet.","Du hast es so gerade noch geschafft. Glück gehabt.","Das war ja fast schon eine richtige Antwort.","Oh, da ist sie. Die Antwort. Endlich.","Hättest du das nicht einfacher haben können?","Ah, da haben wir sie. Die richtige Antwort. Bemerkenswert.","Na endlich. Warum so lange?","Nicht schlecht für jemanden wie dich, oder?","Puh, das hat ja gedauert. Langeweile pur.","Ja, ja, hast du es jetzt endlich?","Das war ja so einfach, oder?","Oh, du hast es doch noch geschafft. Wer hätte das gedacht.","Nicht schlecht, dass du es doch noch gefunden hast.","Wow, das war ja fast schon beeindruckend. Fast.","Das hat ja eine Ewigkeit gedauert, bis du das gefunden hast.","Na bitte, da ist sie. Die Antwort. Endlich.","Oh, du hast es also doch noch geschafft. Interessant.","Gut gemacht, du hast es erneut versucht.","Ah, die Antwort. Endlich mal wieder eine richtige.","Na also, geht doch. Irgendwie.","Wow, du hast es geschafft. Unglaublich.","Oh, du hast es doch noch geschafft. Hätte ich nicht gedacht.","Da ist sie ja. Die Antwort. Endlich.","Nicht schlecht. Nur zwei Versuche gebraucht.","Du hast es also doch noch geschafft. Glück gehabt.","Naja, besser spät als nie, oder?","Ok, endlich.","Nicht so schlecht.","Immerhin richtig.","Gerade so.","War ganz ok.","Gerade geschafft.","Ganz gut.","Na bitte.","Erfolgreich.","Da ist sie.","Nicht übel.","Na also.","Passt.","Besser spät als nie.","Endlich.","Nicht schlecht.","Immerhin.","Nicht zu früh gefreut.","Das war knapp.","Gut gemacht.","Da haben wir sie.","Nicht übel.","In Ordnung.","Das ging ja gerade noch.","Oh, du hast es doch geschafft.","Fast zu spät.","Nicht gerade beeindruckend.","Naja, besser als nichts.","Hätte schlimmer kommen können.","Das war nicht so schwer.","Na also, geht doch.","Na also, immerhin.","Nicht der Rede wert.","Ganz passabel.","Nicht das Gelbe vom Ei.","Das war ja einfach.","Das ging ja gerade noch so.","Nicht übel.","Na also, geschafft.","Immerhin.","Gut gemacht.","Naja, geht so.","Nicht schlecht.","Das war zu erwarten.","Das war ja fast zu einfach.","Nicht schlecht.","Na also, geht doch.","Ganz okay.","Das war knapp."]');
