INSERT INTO quiz_feedback (feedback_key, messages_json) VALUES ('incorrectSecondTry', '["Lass das nächste Mal deine Katze antworten!","Schwache Leistung, Kollege!","Das tut schon weh!","Du hast mehr Fehlschüsse als ein blindes Huhn!","Geh nach Hause, du bist betrunken!","Das war so daneben, dass es fast lustig ist!","Was war das denn?","Glaubst du wirklich, das war eine Antwort?","Das ist traurig, selbst für ein Quiz.","Hast du es überhaupt versucht?","Mein zehnjähriger Cousin hätte das besser gewusst!","Sogar ein Papagei hätte das besser geraten!","Bist du sicher, dass du die richtige Taste gedrückt hast?","Vielleicht solltest du es mit einem anderen Hobby versuchen...","Versuch es mal mit Ratekrimis für Grundschüler!","Das war eindeutig nicht deine Stärke, oder?","Das war so schlecht, ich habe es fast vergessen!","Ich habe schlechte Nachrichten: das war falsch.","Soll ich deinem Gegner Bescheid sagen?","Sag mal, hast du das überhaupt probiert?","Waren das deine ernsthaften Bemühungen?","Wenn du das für richtig hältst, will ich nicht sehen, was falsch ist!","Das war eine harte Landung auf dem Boden der Realität!","Das war schlechter als eine Kapitulation!","Willst du eigentlich gewinnen oder nur spielen?","Es ist fast beeindruckend, wie du es schaffst, so falsch zu sein!","Vielleicht solltest du es mit Tic-Tac-Toe versuchen...","War das wirklich die beste Antwort, die dir eingefallen ist?","Das war eindeutig kein Homerun!","Du bist ungefähr so nah dran wie Nordpol und Südpol!","Das war ein Schlag ins Wasser!","Das war nicht mal nah dran!","Hast du die Frage überhaupt gelesen?","Kannst du überhaupt lesen?","Würdest du eher raten oder flippen?","Es gibt keine Trostpunkte hier!","Das war nicht mal in der Nähe der richtigen Antwort!","Das war so schlimm, dass ich das Bedürfnis habe, es zu löschen!","Ich hoffe, du hast ein gutes Selbstwertgefühl...","Das war noch schlimmer als erwartet!","War das deine beste Anstrengung?","Ist das wirklich das Beste, was du tun kannst?","Du hast die Schönheit des Scheiterns gemeistert!","Falsch! Aber hey, das ist Leben.","Versuche es mit einem Glücksrad!","Hast du heute Morgen gefrühstückt?","Das war so falsch, dass es fast richtig war!","Vielleicht ist es Zeit für ein Nickerchen...","Das war weniger als beeindruckend!","Das war fast so, als würdest du absichtlich falsche Antworten geben!","Haben sie dir deine Maus weggenommen?","Nächstes Mal gib es einfach zu, dass du raten musstest!","Ich hoffe, das war ein Witz.","Das war... interessant!","Was zum Teufel war das?","Das ist wirklich traurig.","Hast du überhaupt eine Ahnung?","Bist du absichtlich so schlecht?","Konzentriere dich besser, das war lächerlich.","Das war einfach nur erbärmlich.","Selbst ein Affe hätte das besser gemacht!","Du könntest ein Denkmal des Scheiterns errichten.","Das war nicht einmal nah dran!","Hast du dir das Gehirn ausgeschaltet?"]');
INSERT INTO quiz_feedback (feedback_key, messages_json) VALUES ('difficultCorrectFirstTry', '["Du bist der unangefochtene Gott des Wissens!","Dein Wissen ist so gigantisch, dass selbst Einstein neidisch wäre!","Du hast die Frage so brillant gelöst, dass selbst Stephen Hawking es nicht besser gekonnt hätte!","Das war nicht einfach nur richtig, das war eine Offenbarung!","Du bist eine wandelnde Enzyklopädie!","Mit dir möchte ich in einer Quizshow sein, denn du bist der Geheimtipp!","Wenn Wissen ein Wettbewerb wäre, hättest du Gold, Silber und Bronze gewonnen!","Dein Gehirn ist ein Supercomputer der Extraklasse!","Halleluja! Die Antwort war so perfekt, dass selbst die Quizmasterin ausflippt!","Hut ab! Du hast die Antwort aus dem Ärmel geschüttelt wie ein Zaubertrick!","Deine Intelligenz strahlt heller als die Sonne!","Das war nicht nur richtig, das war episch!","Du bist das wandelnde Lexikon!","Ich hätte nicht gedacht, dass jemand so grandios antworten kann!","Du bist der reine Genieblitz, der durch die Quizwelt zischt!","Mit dir im Team könnte man jedes Quiz der Welt erobern!","Das war nicht nur korrekt, das war genial!","Deine Antwort war so exakt, dass selbst die Zeitlupe keine Fehler findet!","Du bist der geborene Quizheld, ohne Cape und Superkräfte!","Wenn Perfektion ein Mensch wäre, wärst du es!","Du hast die Antwort so elegant gelöst, dass sie mit einem Oscar ausgezeichnet werden sollte!","Deine Antwort war so göttlich, dass Zeus selbst neidisch wäre!","Mit dir als Gegner ist jedes Quiz ein Kinderspiel für dich!","Du bist das Musterbeispiel für brillantes Quizdenken!","Du hast die Frage so grandios gemeistert, dass sie ins Guinness-Buch der Rekorde gehört!","Das war nicht nur richtig, das war göttlich-legendär!","Dein Wissen ist so episch, dass selbst Sherlock Holmes bei dir in die Lehre gehen würde!","Wenn es ein Superquiz gibt, dann bist du der Übermensch!","Dein Wissen ist so phänomenal, dass die NASA darüber staunt!","Du hast die Antwort so bombastisch rausgehauen, dass die Quizwelt ein Beben spürt!","Deine Antwort war so überragend, dass die Quizmasterin vor Ehrfurcht erblasst!","Das war nicht einfach nur richtig, das war eine Offenbarung des Wissens!","Du bist der einzig wahre Quiz-Guru, der die Antworten aus dem Universum zieht!","Mit dir als Quizpartner könnte man die Welt erobern!","Deine Antwort war so brillant, dass selbst die Computer der Zukunft darüber rätseln!","Das war nicht einfach nur richtig, das war ein Sprung in die unendlichen Weiten des Wissens!","Du bist der wahre Meister des Quizuniversums!","Dein Wissen ist so gigantisch, dass selbst die Pyramiden in Ägypten dagegen klein aussehen!","Wenn das Wissen ein Feuerwerk wäre, wärst du der hellste Stern!","Du hast die Antwort so übertrieben perfekt gegeben, dass die Quizwelt in Schockstarre ist!","Deine Antwort war so legendär, dass selbst die alten Griechen darüber Mythen erzählen würden!","Das war nicht nur richtig, das war eine Meisterleistung der Quizkunst!","Du bist der Überflieger des Quizuniversums!","Mit dir im Quizteam wären selbst die größten Rätsel der Menschheitsgeschichte gelöst!","Deine Antwort war so krass gut, dass sie in die Geschichtsbücher eingehen sollte!","Du bist der König/die Königin des Quizplaneten!","Dein Wissen ist so erhaben, dass selbst Einstein ein Loblied auf dich singen würde!","Das war nicht nur richtig, das war der Olymp des Wissens, den du erklommen hast!","Du bist der heimliche Quizheld, von dem alle sprechen!","Mit dir ist jedes Quiz ein Triumphzug der Intelligenz!","Du bist Gott!","Du bist ultra mega heftig!","Unfassbar gut!","Du bist ein Genie!","Unglaublich!","Phänomenal!","Das ist Wahnsinn!","Du bist ein Naturtalent!","Unvergleichlich!","Göttlich!","Meisterhaft!","Unübertroffen!","Spektakulär!","Das ist einzigartig!","Du bist ein Ass!","Sensationell!","Überragend!","Extravagant!","Du bist der Beste!","Erstaunlich!","Einfach nur krass!","Du bist eine Legende!","Das ist absolute Spitzenklasse!","Du bist eine Wucht!",